// Recibe el payload v2 segmentado (reenviado por /api/submit de Vercel).
// El body llega como objeto (Vercel manda Content-Type: application/json).
let p = $input.first().json.body;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) {} }
p = p || {};

const meta = p.meta || {};
const m1 = p.modulo_1_configuracion || {};
const m2 = p.modulo_2_alertas || {};
const m3 = p.modulo_3_revision_documental || {};
const m4 = p.modulo_4_responsables || {};
const m5 = p.modulo_5_observaciones || {};

const AREA_LABEL = { abastecimiento:'Abastecimiento', cumplimiento:'Cumplimiento', finanzas:'Finanzas', legal:'Legal' };

// ── Resumen textual compacto para los prompts de IA ──
const lines = [];
lines.push('EMPRESA: ' + (meta.empresa || '—') + '  |  CONTACTO: ' + (meta.email || '—'));
lines.push('ÁREAS PARTICIPANTES: ' + ((meta.areasParticipantes || []).join(', ') || 'ninguna'));

// Tipos de evaluación
const tipos = Object.values(m1.tiposEvaluacion || {}).filter(t => t.activo).map(t => t.nombre);
lines.push('\nTIPOS DE EVALUACIÓN ACTIVOS: ' + (tipos.join(', ') || 'ninguno'));
(m1.procesosPersonalizados || []).filter(p => p.activo).forEach(pp => {
  lines.push('  + Proceso custom: ' + pp.nombre + ' (' + (pp.documentos || []).length + ' docs configurados)');
});

// Matriz proceso × área
lines.push('\nMATRIZ PROCESO × ÁREA (quién revisa qué):');
(m1.matrizProcesoArea || []).forEach(row => {
  const revisan = Object.entries(row.areas || {}).filter(([,v]) => v).map(([a]) => AREA_LABEL[a] || a);
  lines.push('  • ' + row.proceso + ' → ' + (revisan.join(', ') || 'NADIE ASIGNADO'));
});

// Alertas por área
lines.push('\nALERTAS CONFIGURADAS POR ÁREA:');
let totalActivas = 0, totalGraves = 0;
Object.entries(m2.porArea || {}).forEach(([area, data]) => {
  const activas = (data.alertas || []).filter(x => x.activa);
  const graves = activas.filter(x => x.severidad === 'grave');
  totalActivas += activas.length; totalGraves += graves.length;
  const porSev = { leve:0, media:0, grave:0 };
  activas.forEach(x => { porSev[x.severidad] = (porSev[x.severidad] || 0) + 1; });
  lines.push('  • ' + (AREA_LABEL[area] || area) + ': ' + activas.length + ' activas '
    + '(' + porSev.grave + ' graves, ' + porSev.media + ' medias, ' + porSev.leve + ' leves)');
  const comentarios = Object.entries(data.comentariosPorGrupo || {}).filter(([,v]) => v && v.trim());
  comentarios.forEach(([g, c]) => lines.push('      ↳ [' + g + '] ' + c));
});

// Responsables y revisores
lines.push('\nRESPONSABLES Y REVISORES:');
Object.entries(m4.porArea || {}).forEach(([area, data]) => {
  const enc = data.encargado || {};
  lines.push('  • ' + (AREA_LABEL[area] || area) + ' — Encargado: ' + (enc.nombre || 'SIN DEFINIR') + (enc.email ? ' <' + enc.email + '>' : ''));
  (data.revisoresAlertasGraves || []).forEach(r => {
    lines.push('      ↳ Revisor: ' + (r.nombre || '—') + ' <' + (r.email || '—') + '> grupos: ' + ((r.grupos || []).join(', ') || 'ninguno'));
  });
});

// Revisión documental (resumen)
lines.push('\nREVISIÓN DOCUMENTAL:');
Object.entries(m3.porArea || {}).forEach(([area, data]) => {
  (data.porProceso || []).forEach(proc => {
    const obs = (proc.documentos || []).filter(d => d.estado === 'con_observacion').length;
    const noAplica = (proc.documentos || []).filter(d => d.estado === 'no_aplica').length;
    const extra = (proc.documentosAdicionales || []).length;
    if (obs || noAplica || extra || (proc.comentario || '').trim()) {
      lines.push('  • ' + (AREA_LABEL[area] || area) + ' / ' + proc.proceso
        + ': ' + obs + ' con observación, ' + noAplica + ' no aplica, ' + extra + ' adicionales'
        + ((proc.comentario || '').trim() ? ' — "' + proc.comentario + '"' : ''));
    }
  });
});

// Observaciones
const obs = Object.entries(m5.observacionesPorArea || {}).filter(([,v]) => v && v.trim());
if (obs.length) {
  lines.push('\nOBSERVACIONES POR ÁREA:');
  obs.forEach(([area, txt]) => lines.push('  • ' + (AREA_LABEL[area] || area) + ': ' + txt));
}
if ((m5.notasSincronizacion || '').trim()) {
  lines.push('\nNOTAS DE ALINEACIÓN FINAL: ' + m5.notasSincronizacion);
}

const resumen = lines.join('\n');

// ── Detección de gaps estructurales (sin IA) ──
const gaps = [];
(m1.matrizProcesoArea || []).forEach(row => {
  const revisan = Object.values(row.areas || {}).filter(v => v).length;
  if (revisan === 0) gaps.push('Proceso "' + row.proceso + '" no tiene ninguna área asignada.');
});
Object.entries(m4.porArea || {}).forEach(([area, data]) => {
  const enc = data.encargado || {};
  if (!enc.nombre || !enc.email) gaps.push('Área ' + (AREA_LABEL[area] || area) + ' sin encargado completo.');
});

return [{ json: {
  // Identificación
  sessionId: meta.sessionId || '',
  empresa: meta.empresa || '',
  email: meta.email || '',
  timestamp: meta.timestamp || new Date().toISOString(),
  areasParticipantes: (meta.areasParticipantes || []).join(', '),

  // Métricas agregadas
  tipos_evaluacion: tipos.join(', '),
  total_procesos: (m1.matrizProcesoArea || []).length,
  total_alertas_activas: totalActivas,
  total_alertas_graves: totalGraves,
  gaps_estructurales: gaps.join(' | ') || 'ninguno',

  // Resumen para los prompts
  resumen_config: resumen,

  // Payload completo (para trazabilidad / reprocesamiento)
  payload_completo: JSON.stringify(p),
} }];

const original = $('Parsear Body').first().json;
const coherencia = $('IA-1 Coherencia').first().json.choices?.[0]?.message?.content
  || $('IA-1 Coherencia').first().json.message?.content || '—';
const politica = $input.first().json.choices?.[0]?.message?.content
  || $input.first().json.message?.content || '—';
return [{ json: { ...original, ai_coherencia: coherencia, ai_politica: politica } }];

